// src/views/user/MyProfile/composables/useModules.js
import { ref, computed } from 'vue'
import { showToast } from '@/components/ToastMessage'
import { user } from '@/api/user'
import { useProfileData } from './useProfileData'

// 所有可用的模块配置
const MODULES_CONFIG = {
  basic_info: { 
    order: 1, 
    visible: true,
    name: '基本信息',
    required: true // 基本信息不可移除
  },
  job_intention: { 
    order: 2, 
    visible: true,
    name: '求职意向',
    required: true // 求职意向为必选模块
  },
  work_experience: { 
    order: 3, 
    visible: true,
    name: '工作经历',
    required: true // 工作经历为必选模块
  },
  education: { 
    order: 4, 
    visible: false,
    name: '教育经历'
  },
  project: { 
    order: 5, 
    visible: false,
    name: '项目经历'
  },
  skill: { 
    order: 6, 
    visible: false,
    name: '专业技能'
  },
  certificate: { 
    order: 7, 
    visible: false,
    name: '证书奖项'
  },
  language: { 
    order: 8, 
    visible: false,
    name: '语言能力'
  },
  portfolio: { 
    order: 9, 
    visible: false,
    name: '作品展示'
  },
  social_link: { 
    order: 10, 
    visible: false,
    name: '社交主页'
  }
}

export function useModules() {
  const { fetchModuleData } = useProfileData()
  const loading = ref(false)
  const modules = ref(new Map())

  // 计算属性：激活的模块
  const activeModules = computed(() => 
    Array.from(modules.value.values())
      .filter(m => m.visible)
      .sort((a, b) => a.order - b.order)
  )

  // 计算属性：未激活的模块
  const inactiveModules = computed(() => 
    Array.from(modules.value.values())
      .filter(m => !m.visible && !m.required)
      .sort((a, b) => a.order - b.order)
  )

  // 初始化模块状态
  const initModules = () => {
    const modulesMap = new Map()
    Object.entries(MODULES_CONFIG).forEach(([key, config]) => {
      modulesMap.set(key, {
        type: key,
        name: config.name,
        order: config.order,
        visible: config.visible,
        required: config.required || false,
        data: null
      })
    })
    modules.value = modulesMap
  }

  // 获取布局和模块数据
  const fetchModulesData = async () => {
    try {
      loading.value = true

      // 1. 初始化模块状态
      if (modules.value.size === 0) {
        initModules()
      }

      // 2. 获取服务器布局
      const response = await user.getProfileLayout()
      if (response.data?.code === 200) {
        const serverLayout = response.data.data?.layout || {}

        // 3. 更新模块状态
        Object.entries(serverLayout).forEach(([key, config]) => {
          const module = modules.value.get(key)
          if (module) {
            module.visible = config.visible
            module.order = config.order
          }
        })

        // 4. 获取激活模块的数据
        await Promise.all(
          activeModules.value.map(async (module) => {
            const data = await fetchModuleData(module.type)
            module.data = data
          })
        )
      }
    } catch (error) {
      console.error('获取模块数据失败:', error)
      showToast('获取模块数据失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 移除模块
  const removeModule = async (moduleType) => {
    try {
      const module = modules.value.get(moduleType)
      if (!module || module.required) {
        throw new Error('该模块不能被移除')
      }

      loading.value = true

      // 1. 准备布局数据
      const layout = {}
      modules.value.forEach((m, key) => {
        layout[key] = {
          order: m.order,
          visible: key === moduleType ? false : m.visible
        }
      })

      // 2. 更新服务器布局
      const response = await user.updateProfileLayout({ 
        data: { layout } 
      })

      if (response.data?.code === 200) {
        // 3. 更新本地状态
        module.visible = false
        module.data = null
        showToast('模块已移除', 'success')
      }
    } catch (error) {
      console.error('移除模块失败:', error)
      showToast(error.message || '移除模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 添加模块
  const addModule = async (moduleType) => {
    try {
      const module = modules.value.get(moduleType)
      if (!module) {
        throw new Error('模块不存在')
      }

      loading.value = true

      // 1. 准备布局数据
      const layout = {}
      modules.value.forEach((m, key) => {
        layout[key] = {
          order: key === moduleType ? activeModules.value.length + 1 : m.order,
          visible: key === moduleType ? true : m.visible
        }
      })

      // 2. 更新服务器布局
      const response = await user.updateProfileLayout({ 
        data: { layout } 
      })

      if (response.data?.code === 200) {
        // 3. 更新本地状态
        module.visible = true
        module.order = activeModules.value.length + 1

        // 4. 获取模块数据
        module.data = await fetchModuleData(moduleType)

        showToast('模块已添加', 'success')
      }
    } catch (error) {
      console.error('添加模块失败:', error)
      showToast(error.message || '添加模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    inactiveModules,
    fetchModulesData,
    addModule,
    removeModule
  }
}
